import React from 'react';
import { Box, Button, Popover, Select, MenuItem, FormControl, InputBase } from '@mui/material';
import { Search as SearchIcon } from '@mui/icons-material';
import CalendarIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Calendar.js";
import SettingsIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Settings.js";
import AddIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Add.js";
import EditIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Edit.js";
import TrashIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Trash.js";
import FAWTypography from '../../FAWTypography';
import { colors } from '../../../../utils/designTokens';

/**
 * WorkflowGridActions - Renders workflow-specific action buttons and popovers
 * This component is used to create bulkActions for the grid
 */
/**
 * WorkflowGridActions - Renders workflow-specific action buttons and popovers
 * This component renders directly in the grid toolbar
 */
const WorkflowGridActions = ({
      selectedTimePeriod,
      filters,
      onTimePeriodClick,
      onManageFiltersClick,
      onCreateFilterClick,
      timePeriodAnchorEl,
      manageFiltersAnchorEl,
      timePeriodSearch,
      onTimePeriodClose,
      onManageFiltersClose,
      onTimePeriodChange,
      onFilterEdit,
      onFilterDelete,
      filteredTimePeriodOptions,
      onTimePeriodSearchChange,
      timePeriodOptions = [
        { value: 'all', label: 'All' },
        { value: '30days', label: '30 Days' },
        { value: '60days', label: '60 Days' },
        { value: '120days', label: '120 Days' },
        { value: '1year', label: '1 Year' }
      ]
    }) => {

    const actions = [];
    const manageFiltersButtonRef = React.useRef(null);

    // Time Period Dropdown using FAWListBox pattern
    actions.push({
      key: 'time-period-button',
      component: (
        <div key="time-period-button" className="atlas-aggrid-timeperiod-filter" style={{ position: 'relative', display: 'inline-block' }}>
          <FormControl 
            variant="outlined"
            sx={{ 
              minWidth: '217px',
              position: 'relative'
            }}
          >
            <Select
              value={selectedTimePeriod}
              onChange={(e) => onTimePeriodChange(e)}
              displayEmpty
              renderValue={() => (
                <Box sx={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                  <CalendarIcon size="sm" />
                  <span>Time period: {timePeriodOptions.find(opt => opt.value === selectedTimePeriod)?.label || 'All'}</span>
                </Box>
              )}
              onOpen={() => {
                // Select component handles its own open state
              }}
              onClose={() => {
                onTimePeriodClose();
                if (onTimePeriodSearchChange) {
                  onTimePeriodSearchChange('');
                }
              }}
              sx={{
                height: '40px',
                textTransform: 'none',
                fontSize: '16px',
                fontWeight: 600,
                borderRadius: '8px',
                border: '1px solid transparent',
                color: colors.type.default,
                backgroundColor: colors.background.default,
                padding: '8px 12px',
                fontFamily: '"Plus Jakarta Sans", sans-serif',
                lineHeight: '25.5px',
                '&:hover': {
                  backgroundColor: colors.background.secondary,
                  border: '1px solid transparent'
                },
                '& .MuiSelect-select': {
                  padding: 0,
                  paddingRight: '32px', // Space for dropdown icon
                  display: 'flex',
                  alignItems: 'center'
                },
                '& .MuiSelect-icon': {
                  color: colors.type.secondary, // Ensure dropdown icon is visible
                  right: '12px'
                },
                '& .MuiOutlinedInput-notchedOutline': {
                  border: 'none'
                },
                '&.Mui-focused .MuiOutlinedInput-notchedOutline': {
                  border: 'none'
                },
                '&.Mui-focused': {
                  border: '1px solid transparent'
                }
              }}
              MenuProps={{
                anchorOrigin: {
                  vertical: 'bottom',
                  horizontal: 'left',
                },
                transformOrigin: {
                  vertical: 'top',
                  horizontal: 'left',
                },
                PaperProps: {
                  sx: {
                    backgroundColor: colors.background.default,
                    borderRadius: '8px',
                    boxShadow: '0px 0px 2px 0px rgba(0,0,0,0.1), 0px 8px 16px 0px rgba(0,0,0,0.1)',
                    minWidth: '200px',
                    maxWidth: '300px',
                    marginTop: '4px',
                    border: 'none',
                    overflow: 'hidden',
                    zIndex: 1300
                  }
                },
                BackdropProps: {
                  sx: {
                    backgroundColor: 'transparent'
                  }
                }
              }}
            >
              {/* Search Input */}
              <MenuItem disabled sx={{ padding: 0, minHeight: 'auto' }}>
                <Box sx={{ 
                  display: 'flex',
                  flexDirection: 'column',
                  gap: 0,
                  width: '100%',
                  padding: '8px 12px'
                }}>
                  <Box sx={{ 
                    display: 'flex',
                    alignItems: 'center',
                    gap: '8px',
                    height: '40px',
                    width: '100%'
                  }}>
                    <SearchIcon size="md" style={{ color: colors.type.secondary }} />
                    <InputBase
                      placeholder="Search"
                      value={timePeriodSearch || ''}
                      onChange={(e) => {
                        e.stopPropagation();
                        if (onTimePeriodSearchChange) {
                          onTimePeriodSearchChange(e.target.value);
                        }
                      }}
                      onClick={(e) => e.stopPropagation()}
                      sx={{
                        flex: 1,
                        fontSize: '16px',
                        fontFamily: '"Plus Jakarta Sans", sans-serif',
                        fontWeight: 400,
                        lineHeight: '24px',
                        color: colors.type.secondary,
                        letterSpacing: '0.2px'
                      }}
                    />
                  </Box>
                  <Box sx={{ 
                    backgroundColor: colors.ui.border.static,
                    height: '1px',
                    width: '100%',
                    marginTop: '8px'
                  }} />
                </Box>
              </MenuItem>
              
              {/* Radio Options */}
              {(filteredTimePeriodOptions || timePeriodOptions).map((option) => (
                <MenuItem
                  key={option.value}
                  value={option.value}
                  selected={selectedTimePeriod === option.value}
                  onClick={() => onTimePeriodChange({ target: { value: option.value } })}
                  sx={{
                    padding: '12px',
                    display: 'flex',
                    gap: '12px',
                    alignItems: 'center',
                    backgroundColor: selectedTimePeriod === option.value ? (colors.background.accentRed || '#ffedeb') : 'transparent',
                    '&.Mui-selected': {
                      backgroundColor: colors.background.accentRed || '#ffedeb',
                      '&:hover': {
                        backgroundColor: colors.background.accentRed || '#ffedeb'
                      }
                    }
                  }}
                >
                  <Box sx={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: '12px',
                    width: '100%'
                  }}>
                    <Box sx={{
                      backgroundColor: colors.background.default,
                      border: `1.4px solid ${colors.type.default}`,
                      borderRadius: '9999px',
                      width: '24px',
                      height: '24px',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      flexShrink: 0
                    }}>
                      {selectedTimePeriod === option.value && (
                        <Box sx={{
                          width: '8px',
                          height: '8px',
                          borderRadius: '50%'
                        }} />
                      )}
                    </Box>
                    <Box sx={{
                      flex: 1,
                      fontFamily: '"Plus Jakarta Sans", sans-serif',
                      fontWeight: 400,
                      fontSize: '16px',
                      lineHeight: '24px',
                      color: colors.type.default,
                      letterSpacing: '0.2px',
                      textAlign: 'left'
                    }}>
                      {option.label}
                    </Box>
                  </Box>
                </MenuItem>
              ))}
            </Select>
          </FormControl>
        </div>
      )
    });

    // Create Filter Button
    if (onCreateFilterClick) {
      actions.push({
        key: 'create-filter-button',
        component: (
          <Button
            key="create-filter-button"
            variant="outlined"
            onClick={onCreateFilterClick}
            startIcon={<AddIcon size="sm" />}
            sx={{
              height: '40px',
              minWidth: '207px',
              textTransform: 'none',
              fontSize: '16px',
              fontWeight: 600,
              borderRadius: '8px',
              border: 'none',
              color: colors.type.default,
              backgroundColor: colors.background.default,
              padding: '8px 12px',
              fontFamily: '"Plus Jakarta Sans", sans-serif',
              lineHeight: '25.5px',
              '&:hover': {
                backgroundColor: colors.background.secondary
              },
              '& .MuiButton-startIcon': {
                marginRight: '8px',
                marginLeft: 0
              }
            }}
          >
            Create a new filter
          </Button>
        )
      });
    }

    // Manage Filters Button with Popover
    actions.push({
      key: 'manage-filters-button',
      component: (
        <div key="manage-filters-button" className="atlas-aggrid-manage-filters" style={{ position: 'relative', display: 'inline-block' }}>
          <FAWButton
            ref={manageFiltersButtonRef}
            variant="outlined"
            onClick={(e) => {
              const anchorElement = manageFiltersButtonRef.current || e.currentTarget;
              if (onManageFiltersClick) {
                onManageFiltersClick({ currentTarget: anchorElement });
              }
            }}
            startIcon={<SettingsIcon size="sm" />}
          >
            Manage filters
          </FAWButton>
          
          <Popover
            open={Boolean(manageFiltersAnchorEl)}
            anchorEl={manageFiltersAnchorEl || manageFiltersButtonRef.current}
            onClose={onManageFiltersClose}
            anchorOrigin={{
              vertical: 'bottom',
              horizontal: 'right',
            }}
            transformOrigin={{
              vertical: 'top',
              horizontal: 'right',
            }}
            disableAutoFocus
            disableEnforceFocus
            disableRestoreFocus
            className="atlas-aggrid-manage-filters-popover"
            PaperProps={{
              sx: {
                backgroundColor: '#ffffff !important',
                borderRadius: '8px',
                boxShadow: '0px 0px 2px 0px rgba(0,0,0,0.1), 0px 8px 16px 0px rgba(0,0,0,0.1)',
                minWidth: '480px',
                maxWidth: '480px',
                width: '480px',
                marginTop: '4px',
                border: 'none',
                overflow: 'hidden',
                zIndex: 1300
              }
            }}
            BackdropProps={{
              sx: {
                backgroundColor: 'transparent'
              }
            }}
          >
            <Box sx={{ 
              backgroundColor: '#ffffff',
              display: 'flex',
              flexDirection: 'column',
              overflow: 'hidden'
            }}>
              {/* Header */}
              <Box sx={{ 
                display: 'flex',
                flexDirection: 'column',
              }}>
                <FAWTypography variant="h6" sx={{ 
                  fontWeight: 600, 
                  fontSize: '16px',
                }}>
                  Manage filters
                </FAWTypography>
              </Box>

              {/* Filters Section */}
              <Box sx={{ 
                display: 'flex',
                flexDirection: 'column',
                gap: 0,
                maxHeight: '400px',
                overflowY: 'auto',
              }}>
                {/* Section Header */}
                <Box sx={{
                  padding: '12px 0',
                  borderBottom: '1px solid #dadada'
                }}>
                  <FAWTypography variant="body2" sx={{ 
                    fontWeight: 600, 
                    fontSize: '12px',
                  }}>
                    Filters
                  </FAWTypography>
                </Box>

                {/* Filter Items */}
                {filters.map((filter) => (
                  <Box key={filter.id} sx={{
                    display: 'flex',
                    gap: '16px',
                    alignItems: 'center',
                    padding: '12px'
                  }}>
                    {/* Filter Info */}
                    <Box sx={{ flex: 1 }}>
                      <FAWTypography variant="body2" sx={{ 
                        fontWeight: 400, 
                        fontSize: '16px', 
                        lineHeight: '24px',
                        letterSpacing: '0.2px',
                        color: '#282e37'
                      }}>
                        {filter.name} ({filter.count})
                      </FAWTypography>
                    </Box>

                    {/* Action Buttons */}
                    <Box sx={{ display: 'flex', gap: '16px' }}>
                      <Button 
                        variant="text" 
                        size="small" 
                        disabled={!filter.actualId || parseInt(filter.actualId, 10) <= 0 || filter.name === 'All Workflows'}
                        onClick={(e) => {
                          e.stopPropagation();
                          e.preventDefault();
                          if (onFilterEdit) {
                            onFilterEdit(filter.id);
                          }
                        }}
                        sx={{ 
                          minWidth: 'auto', 
                          padding: '12px',
                          borderRadius: '12px',
                        }}
                      >
                        <EditIcon size="lg" style={{ color: (!filter.actualId || parseInt(filter.actualId, 10) <= 0 || filter.name === 'All Workflows') ? '#9ca3af' : '#282e37' }} />
                      </Button>
                      <Button 
                        variant="text" 
                        size="small" 
                        disabled={filter.enabled || !filter.actualId || filter.name === 'All Workflows'}
                        onClick={(e) => {
                          e.stopPropagation();
                          e.preventDefault();
                          if (!filter.enabled && filter.actualId && filter.name !== 'All Workflows' && onFilterDelete) {
                            onFilterDelete(filter.id);
                          }
                        }}
                        sx={{ 
                          minWidth: 'auto', 
                          padding: '12px',
                          borderRadius: '12px',
                        }}
                      >
                        <TrashIcon 
                          size="lg" 
                          style={{ 
                            color: (filter.enabled || !filter.actualId || filter.name === 'All Workflows') ? '#9ca3af' : '#282e37'
                          }} 
                        />
                      </Button>
                    </Box>
                  </Box>
                ))}
              </Box>
              
              {/* Close Button */}
              <Box sx={{ 
                display: 'flex', 
                justifyContent: 'flex-end', 
                alignItems: 'center',
                minHeight: '40px',
                padding: 0
              }}>
                <FAWButton variant="contained" size="small" onClick={onManageFiltersClose} label="Close" />
              </Box>
            </Box>
          </Popover>
        </div>
      )
    });


    return (
      <React.Fragment>
        {actions.map(action => (
          <React.Fragment key={action.key}>
            {action.component}
          </React.Fragment>
        ))}
      </React.Fragment>
    );
};

export default WorkflowGridActions;

