import React from 'react';
import { Box } from '@mui/material';
import FAWErrorBoundary from '../../errorHandling/FAWErrorBoundary';
import WorkflowGridActions from './WorkflowGridActions';
import { useWorkflowGridState } from '../hooks/useWorkflowGridState';
import { useWorkflowGridHandlers } from '../hooks/useWorkflowGridHandlers';
import '../styles/workflow-grid.css';

/**
 * WorkflowGridManager - Manages workflow-specific grid functionality
 * Handles time period filtering, filter management, and workflow buttons
 * 
 * @param {Object} props
 * @param {Array} props.rowData - Grid row data
 * @param {Function} props.onRowDataChange - Callback when filtered row data changes
 * @param {Array} props.filterData - Initial filter data
 * @param {String} props.initialTimePeriod - Initial time period value
 * @param {Function} props.onCreateFilterClick - Handler for create filter button clicks
 * @param {Function} props.onToolbarChange - Callback to provide toolbar component to parent
 * @param {String} props.filterType - Filter type (SecurimateWorkItemFilterGroup or SecurimateWorkItemTaskFilterGroup)
 */
const WorkflowGridManager = ({
  rowData = [],
  onRowDataChange,
  filterData = [],
  initialTimePeriod = 'all',
  onCreateFilterClick = null,
  onToolbarChange,
  filterType = 'SecurimateWorkItemFilterGroup'
}) => {
  // Use custom hooks for state management and handlers
  const state = useWorkflowGridState({
    rowData,
    filterData,
    initialTimePeriod
  });
  
  const handlers = useWorkflowGridHandlers({
    rowData,
    onRowDataChange,
    onCreateFilterClick,
    setFilteredRowData: state.setFilteredRowData,
    setSelectedTimePeriod: state.setSelectedTimePeriod,
    setFilters: state.setFilters,
    filters: state.filters,
    setTimePeriodAnchorEl: state.setTimePeriodAnchorEl,
    setManageFiltersAnchorEl: state.setManageFiltersAnchorEl,
    setTimePeriodSearch: state.setTimePeriodSearch,
    filterDataByTimePeriod: state.filterDataByTimePeriod,
    timePeriodSearch: state.timePeriodSearch,
    filterType: filterType
  });

  // Render workflow actions component
  const workflowActionsComponent = React.useMemo(() => {
    return (
      <WorkflowGridActions
        selectedTimePeriod={state.selectedTimePeriod}
        filters={state.filters}
        onTimePeriodClick={handlers.handleTimePeriodClick}
        onManageFiltersClick={handlers.handleManageFiltersClick}
        onCreateFilterClick={handlers.handleCreateFilterClick}
        timePeriodAnchorEl={state.timePeriodAnchorEl}
        manageFiltersAnchorEl={state.manageFiltersAnchorEl}
        timePeriodSearch={state.timePeriodSearch}
        onTimePeriodClose={handlers.handleTimePeriodClose}
        onManageFiltersClose={handlers.handleManageFiltersClose}
        onTimePeriodChange={handlers.handleTimePeriodChange}
        filteredTimePeriodOptions={state.filteredTimePeriodOptions}
        onTimePeriodSearchChange={state.setTimePeriodSearch}
        timePeriodOptions={state.timePeriodOptions}
      />
    );
  }, [
    state.selectedTimePeriod,
    state.filters,
    state.timePeriodAnchorEl,
    state.manageFiltersAnchorEl,
    state.timePeriodSearch,
    state.filteredTimePeriodOptions,
    state.timePeriodOptions,
    handlers
  ]);

  // Update toolbar when component changes
  React.useEffect(() => {
    if (onToolbarChange) {
      // Pass the workflow toolbar component to parent
      onToolbarChange(workflowActionsComponent);
    }
  }, [workflowActionsComponent, onToolbarChange]);

  // Update parent when filtered data changes
  React.useEffect(() => {
    if (onRowDataChange) {
      onRowDataChange(state.filteredRowData);
    }
  }, [state.filteredRowData, onRowDataChange]);

  return (
    <FAWErrorBoundary
      title="Workflow Grid Error"
      message="An error occurred while loading the workflow grid. Please try again or contact support if the problem persists."
      showDetails={true}
      onError={(error, errorInfo) => {
        console.error('WorkflowGridManager Error:', error, errorInfo);
      }}
    >
      <Box className="workflow-grid-manager-container" sx={{ display: 'none' }}>
        {/* This component manages state and passes actions via bulkActions */}
        {/* The actual UI is rendered through bulkActions in the grid */}
      </Box>
    </FAWErrorBoundary>
  );
};

export default WorkflowGridManager;

